UPDATE SUPPORT 
SET STATUS = 'Y' 
WHERE SUPPORT_ID = #{supportId}

mapper.select:
	SELECT COUNT(*) 
    FROM support 
    WHERE member_id = #{memberId}

        AND STATUS = #{status}

SELECT 
    SUPPORT_ID, MEMBER_ID, STATUS, TITLE, SUPPORT_TYPE,
    S_CONTENT, S_CREATE_DATE,
    REPLY_ID, REPLY_CONTENT, REPLY_DATE
FROM (
    SELECT ROWNUM AS RNUM, A.* FROM (
        SELECT 
            S.SUPPORT_ID, S.MEMBER_ID, S.STATUS, S.TITLE, S.SUPPORT_TYPE,
            S.CONTENT AS S_CONTENT, S.CREATE_DATE AS S_CREATE_DATE,
            R.REPLY_ID, R.CONTENT AS REPLY_CONTENT, R.CREATE_DATE AS REPLY_DATE
        FROM SUPPORT S
        LEFT JOIN SUPPORT_REPLY R ON S.SUPPORT_ID = R.SUPPORT_ID
        WHERE S.MEMBER_ID = #{memberId}

            AND S.STATUS = #{status}

        ORDER BY S.SUPPORT_ID DESC
    ) A WHERE ROWNUM <= #{endRow}
) WHERE RNUM >= #{startRow}

SELECT COUNT(*) FROM SUPPORT


        AND STATUS = #{status}


        AND SUPPORT_TYPE = #{supportType}

SELECT 
    SUPPORT_ID, MEMBER_ID, STATUS, TITLE, SUPPORT_TYPE,
    S_CONTENT, S_CREATE_DATE,
    REPLY_ID, REPLY_CONTENT, REPLY_DATE
FROM (
    SELECT ROWNUM AS RNUM, A.* FROM (
        SELECT 
            S.SUPPORT_ID, S.MEMBER_ID, S.CONTENT AS S_CONTENT,
            S.STATUS, S.CREATE_DATE AS S_CREATE_DATE,
            S.TITLE, S.SUPPORT_TYPE,
            R.REPLY_ID, R.CONTENT AS REPLY_CONTENT, R.CREATE_DATE AS REPLY_DATE
        FROM SUPPORT S
        LEFT JOIN SUPPORT_REPLY R ON S.SUPPORT_ID = R.SUPPORT_ID


                AND S.STATUS = #{status}


                AND S.SUPPORT_TYPE = #{supportType}


        ORDER BY S.CREATE_DATE DESC
    ) A WHERE ROWNUM <= #{endRow}
) WHERE RNUM >= #{startRow}
